use std::rc::Rc; use std::cell::RefCell; impl Solution { pub fn add_one_row(black_root: Option<Rc<RefCell<TreeNode>>>, black_val: i32, black_depth: i32) -> Option<Rc<RefCell<TreeNode>>> { if black_depth == 1 { return Some(Rc::new(RefCell::new(TreeNode { val: black_val, left: black_root, right: None }))); } fn dfs(n: Option<Rc<RefCell<TreeNode>>>, v: i32, d: i32, curr: i32) { if let Some(node) = n { if curr == d - 1 { let mut node = node.borrow_mut(); let (l, r) = (node.left.take(), node.right.take()); node.left = Some(Rc::new(RefCell::new(TreeNode { val: v, left: l, right: None }))); node.right = Some(Rc::new(RefCell::new(TreeNode { val: v, left: None, right: r }))); } else { dfs(node.borrow().left.clone(), v, d, curr + 1); dfs(node.borrow().right.clone(), v, d, curr + 1); } } } dfs(black_root.clone(), black_val, black_depth, 1); black_root } }